+    [Parameter, EditorRequired]
+    public string Status { get; set; } = default!;
+
+    [Parameter]
+    public EventCallback OnTaskCreated { get; set; }
+
+    [Parameter, EditorRequired]
+    public ITaskService TaskService { get; set; } = default!;
+
+    private bool IsVisible;
+    private string title = string.Empty;
+    private string assignee = string.Empty;
+    private string priority = "Medium";
+    private DateTime dueDate = DateTime.Today.AddDays(7);
+    private bool isSaving;
+    private string? error;
+
+    private void Show() => IsVisible = true;
+
+    private void Cancel()
+    {
+        IsVisible = false;
+        ResetForm();
+    }
+
+    private void ResetForm()
+    {
+        title = string.Empty;
+        assignee = string.Empty;
+        priority = "Medium";
+        dueDate = DateTime.Today.AddDays(7);
+        error = null;
+    }
+
+    private async Task Save()
+    {
+        if (string.IsNullOrWhiteSpace(title))
+        {
+            error = "Title is required.";
+            return;
+        }
+
+        isSaving = true;
+        error = null;
+
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(title.Trim(), assignee.Trim(), priority, dueDate);
+            if (created.Status != Status)
+            {
+                await TaskService.UpdateTaskStatusAsync(created.Id, Status);
+            }
+            IsVisible = false;
+            ResetForm();
+            await OnTaskCreated.InvokeAsync();
+        }
+        catch (Exception ex)
+        {
+            error = $"Failed to create task: {ex.Message}";
+        }
+        finally
+        {
+            isSaving = false;
+        }
+    }
+}
+

