@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Kanban Board</h2>

@if (isLoading)
{
    <p class="board-loading">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        @for (var i = 0; i < columns.Length; i++)
        {
            var colIndex = i;
            var colName = columns[colIndex];
            var colTasks = GetFilteredTasksForColumn(colName);

            <BoardColumn ColumnName="@colName"
                         Tasks="colTasks"
                         CanMoveLeft="colIndex > 0"
                         CanMoveRight="colIndex < columns.Length - 1"
                         OnMoveLeft="id => MoveTask(id, colIndex, -1)"
                         OnMoveRight="id => MoveTask(id, colIndex, 1)"
                         OnTaskCreated="LoadTasks"
                         TaskService="TaskService" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = [];
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private List<TaskItem> GetFilteredTasksForColumn(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return tasks.ToList();
    }

    private async Task MoveTask(int taskId, int currentColIndex, int direction)
    {
        var newColIndex = currentColIndex + direction;
        if (newColIndex < 0 || newColIndex >= columns.Length) return;

        var newStatus = columns[newColIndex];

        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            await LoadTasks();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }
}

